export type Vote = {
  userId: string
  value: 1 | -1
}

export type Reply = {
  id: string
  threadId: string
  author: string
  body: string
  createdAt: string
  votes: Vote[]
}

export type Thread = {
  id: string
  title: string
  body: string
  author: string
  createdAt: string
  votes: Vote[]
  replies: Reply[]
}

export type ForumData = {
  threads: Thread[]
}

export type SortMode = 'newest' | 'top' | 'active'

export type CreateThreadInput = {
  title: string
  body: string
  author: string
}

export type CreateReplyInput = {
  threadId: string
  body: string
  author: string
}

export type VoteInput = {
  targetId: string
  userId: string
  value: 1 | -1
}

import type { ForumData, Thread, Reply, CreateThreadInput, CreateReplyInput, VoteInput, SortMode } from './types'

const DATA_PATH = 'data/forum.json'

const generateId = (): string => crypto.randomUUID()

const loadData = async (): Promise<ForumData> => {
  const file = Bun.file(DATA_PATH)
  if (await file.exists()) {
    return file.json()
  }
  return { threads: [] }
}

const saveData = async (data: ForumData): Promise<void> => {
  await Bun.write(DATA_PATH, JSON.stringify(data, null, 2))
}

export const getThreads = async (sort: SortMode = 'newest', search?: string): Promise<Thread[]> => {
  const data = await loadData()
  let threads = data.threads

  if (search) {
    const query = search.toLowerCase()
    threads = threads.filter((t) => t.title.toLowerCase().includes(query))
  }

  const scoreOf = (t: Thread): number =>
    t.votes.reduce((sum, v) => sum + v.value, 0)

  switch (sort) {
    case 'newest':
      threads.sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime())
      break
    case 'top':
      threads.sort((a, b) => scoreOf(b) - scoreOf(a))
      break
    case 'active':
      threads.sort((a, b) => b.replies.length - a.replies.length)
      break
  }

  return threads
}

export const getThread = async (id: string): Promise<Thread | undefined> => {
  const data = await loadData()
  return data.threads.find((t) => t.id === id)
}

export const createThread = async (input: CreateThreadInput): Promise<Thread> => {
  const data = await loadData()
  const thread: Thread = {
    id: generateId(),
    title: input.title,
    body: input.body,
    author: input.author,
    createdAt: new Date().toISOString(),
    votes: [],
    replies: [],
  }
  data.threads.push(thread)
  await saveData(data)
  return thread
}

export const createReply = async (input: CreateReplyInput): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find((t) => t.id === input.threadId)
  if (!thread) return null

  const reply: Reply = {
    id: generateId(),
    threadId: input.threadId,
    author: input.author,
    body: input.body,
    createdAt: new Date().toISOString(),
    votes: [],
  }
  thread.replies.push(reply)
  await saveData(data)
  return reply
}

export const voteThread = async (input: VoteInput): Promise<Thread | null> => {
  const data = await loadData()
  const thread = data.threads.find((t) => t.id === input.targetId)
  if (!thread) return null

  const existing = thread.votes.findIndex((v) => v.userId === input.userId)
  if (existing >= 0) {
    if (thread.votes[existing].value === input.value) {
      thread.votes.splice(existing, 1)
    } else {
      thread.votes[existing].value = input.value
    }
  } else {
    thread.votes.push({ userId: input.userId, value: input.value })
  }

  await saveData(data)
  return thread
}

export const voteReply = async (threadId: string, input: VoteInput): Promise<Reply | null> => {
  const data = await loadData()
  const thread = data.threads.find((t) => t.id === threadId)
  if (!thread) return null

  const reply = thread.replies.find((r) => r.id === input.targetId)
  if (!reply) return null

  const existing = reply.votes.findIndex((v) => v.userId === input.userId)
  if (existing >= 0) {
    if (reply.votes[existing].value === input.value) {
      reply.votes.splice(existing, 1)
    } else {
      reply.votes[existing].value = input.value
    }
  } else {
    reply.votes.push({ userId: input.userId, value: input.value })
  }

  await saveData(data)
  return reply
}

