const scoreOf = (votes: { value: number }[]): number =>
  votes.reduce((sum, v) => sum + v.value, 0)

const timeAgo = (dateStr: string): string => {
  const now = Date.now()
  const then = new Date(dateStr).getTime()
  const diff = Math.floor((now - then) / 1000)

  if (diff < 60) return 'just now'
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`
  if (diff < 86400) return `${Math.floor(diff / 3600)}h ago`
  return `${Math.floor(diff / 86400)}d ago`
}

export const renderThreadList = (threads: Thread[], sort: SortMode, search: string): string => {
  const sortButtons = (['newest', 'top', 'active'] as SortMode[]).map((mode) =>
    h('button', {
      style: mode === sort ? styles.sortButtonActive : styles.sortButton,
      'p-trigger': `sort-${mode}`,
    }, mode === 'newest' ? 'Newest' : mode === 'top' ? 'Top Voted' : 'Most Active')
  )

  const threadCards = threads.length > 0
    ? threads.map((thread) => {
        const score = scoreOf(thread.votes)
        return h('div', { style: styles.threadCard, 'p-trigger': `view-thread-${thread.id}` },
          h('div', { style: { display: 'flex', gap: '12px', alignItems: 'flex-start' } },
            h('div', { style: styles.voteControls },
              h('button', { style: styles.voteButton, 'p-trigger': `upvote-thread-${thread.id}` }, '\u25B2'),
              h('span', { style: { ...styles.voteScore, color: score > 0 ? '#2d8a4e' : score < 0 ? '#c0392b' : '#888' } }, String(score)),
              h('button', { style: styles.voteButton, 'p-trigger': `downvote-thread-${thread.id}` }, '\u25BC'),
            ),
            h('div', { style: { flex: '1' } },
              h('h3', { style: styles.threadTitle }, thread.title),
              h('div', { style: styles.threadMeta },
                h('span', {}, `by ${thread.author}`),
                h('span', {}, timeAgo(thread.createdAt)),
                h('span', {}, `${thread.replies.length} ${thread.replies.length === 1 ? 'reply' : 'replies'}`),
              ),
            ),
          ),
        )
      })
    : [h('div', { style: styles.emptyState },
        search
          ? `No threads matching "${search}"`
          : 'No threads yet. Start a discussion!'
      )]

  const template = h(Fragment, {},
    h('div', { style: styles.page },
      h('div', { style: styles.header },
        h('h1', { style: styles.title }, 'Discussion Forum'),
        h('button', { style: styles.newThreadButton, 'p-trigger': 'new-thread' }, '+ New Thread'),
      ),
      h('div', { style: styles.searchBar },
        h('input', {
          type: 'text',
          placeholder: 'Search threads...',
          style: styles.searchInput,
          value: search,
          'p-trigger': 'search',
          'p-target': 'search-input',
        }),
      ),
      h('div', { style: styles.sortControls }, ...sortButtons),
      h('div', { 'p-target': 'thread-list' }, ...threadCards),
    ),
  )

  return createSSR(template)
}

