import type { SortMode, CreateThreadInput, CreateReplyInput, VoteInput } from './types'
import { getThreads, getThread, createThread, createReply, voteThread, voteReply } from './store'
import { renderThreadList, renderNewThreadForm, renderThreadDetail } from './ui'

type RouteResponse = {
  status: number
  headers: Record<string, string>
  body: string
}

const jsonResponse = (data: unknown, status = 200): RouteResponse => ({
  status,
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify(data),
})

const htmlResponse = (html: string, status = 200): RouteResponse => ({
  status,
  headers: { 'Content-Type': 'text/html; charset=utf-8' },
  body: html,
})

const errorResponse = (message: string, status = 400): RouteResponse =>
  jsonResponse({ error: message }, status)

export const handleRequest = async (method: string, path: string, body?: unknown): Promise<RouteResponse> => {
  const url = new URL(path, 'http://localhost')
  const segments = url.pathname.split('/').filter(Boolean)

  // GET / — render thread list page
  if (method === 'GET' && segments.length === 0) {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('search') || ''
    const threads = await getThreads(sort, search || undefined)
    return htmlResponse(renderThreadList(threads, sort, search))
  }

  // GET /new — render new thread form
  if (method === 'GET' && segments[0] === 'new') {
    return htmlResponse(renderNewThreadForm())
  }

  // GET /threads/:id — render thread detail
  if (method === 'GET' && segments[0] === 'threads' && segments[1]) {
    const thread = await getThread(segments[1])
    if (!thread) return errorResponse('Thread not found', 404)
    return htmlResponse(renderThreadDetail(thread))
  }

  // POST /threads — create new thread
  if (method === 'POST' && segments[0] === 'threads' && !segments[1]) {
    const input = body as CreateThreadInput
    if (!input?.title?.trim() || !input?.body?.trim() || !input?.author?.trim()) {
      return errorResponse('Title, body, and author are required')
    }
    const thread = await createThread({
      title: input.title.trim(),
      body: input.body.trim(),
      author: input.author.trim(),
    })
    return jsonResponse(thread, 201)
  }

  // POST /threads/:id/replies — add reply
  if (method === 'POST' && segments[0] === 'threads' && segments[2] === 'replies') {
    const input = body as CreateReplyInput
    if (!input?.body?.trim() || !input?.author?.trim()) {
      return errorResponse('Body and author are required')
    }
    const reply = await createReply({
      threadId: segments[1],
      body: input.body.trim(),
      author: input.author.trim(),
    })
    if (!reply) return errorResponse('Thread not found', 404)
    return jsonResponse(reply, 201)
  }

  // POST /threads/:id/vote — vote on thread
  if (method === 'POST' && segments[0] === 'threads' && segments[2] === 'vote') {
    const input = body as VoteInput
    if (!input?.userId || !input?.value || ![1, -1].includes(input.value)) {
      return errorResponse('userId and value (1 or -1) are required')
    }
    const thread = await voteThread({
      targetId: segments[1],
      userId: input.userId,
      value: input.value,
    })
    if (!thread) return errorResponse('Thread not found', 404)
    return jsonResponse(thread)
  }

  // POST /threads/:id/replies/:replyId/vote — vote on reply
  if (method === 'POST' && segments[0] === 'threads' && segments[2] === 'replies' && segments[4] === 'vote') {
    const input = body as VoteInput
    if (!input?.userId || !input?.value || ![1, -1].includes(input.value)) {
      return errorResponse('userId and value (1 or -1) are required')
    }
    const reply = await voteReply(segments[1], {
      targetId: segments[3],
      userId: input.userId,
      value: input.value,
    })
    if (!reply) return errorResponse('Reply not found', 404)
    return jsonResponse(reply)
  }

  // GET /api/threads — JSON thread list
  if (method === 'GET' && segments[0] === 'api' && segments[1] === 'threads') {
    const sort = (url.searchParams.get('sort') as SortMode) || 'newest'
    const search = url.searchParams.get('search') || ''
    const threads = await getThreads(sort, search || undefined)
    return jsonResponse(threads)
  }

  return errorResponse('Not found', 404)
}

import { handleRequest } from './routes'

const PORT = Number(process.env.PORT) || 3000

const server = Bun.serve({
  port: PORT,
  fetch: async (req) => {
    const url = new URL(req.url)
    const method = req.method

    let body: unknown = undefined
    if (method === 'POST' || method === 'PUT') {
      const contentType = req.headers.get('content-type') || ''
      if (contentType.includes('application/json')) {
        body = await req.json()
      }
    }

    const path = url.pathname + url.search
    const result = await handleRequest(method, path, body)

    return new Response(result.body, {
      status: result.status,
      headers: result.headers,
    })
  },
})

